// Helper: extract slug from "creator/slug" or "slug" format
function getSlugFromEntry(entry) {
  if (typeof entry === 'string') return entry;
  return entry[0];
}

// Helper: determine skill status
// "compatible_installed" — pre-installed frontend
// "compatible" — backend-available, whistant-compatible, not pre-installed
// "not_compatible" — deep screened, requires Python/shell/binaries, can't work (includes deprecated APIs)
// "may_work_directly" — JS-only code found, simple screened, need testing
// "may_not_work_directly" — not indexed, has non-JS code, can't use
function getSkillStatus(entry) {
  var slug = getSlugFromEntry(entry);
  if (COMPATIBLE_INSTALLED.has(slug)) return 'compatible_installed';
  if (COMPATIBLE.has(slug)) return 'compatible';
  if (NOT_COMPATIBLE.has(slug)) return 'not_compatible';
  return 'may_work_directly'; // JS-only found in catalog
}

